# verify.jl -- cross-check wolframscript (oracles.txt) against Python
# (oracles_python.txt) for the Phase 3 Coefficients oracle, then emit
# the canonical pinned values to test/_oracle_coefficients.jl.
#
# Usage:  julia --project=. external/probes/coefficients-oracle/verify.jl
# Run AFTER:
#   wolframscript -file external/probes/coefficients-oracle/capture.wl
#   python3 external/probes/coefficients-oracle/capture.py
#
# This script enforces that the two independent oracles agree to within
# Float64 round-off (3.1.1, 3.1.2) and 78-digit decimal string match
# (3.1.4). 3.1.3 (Weierstrass) is wolframscript-only; we rely on its
# internal cross-check (AsymptoticDSolveValue vs Series[WeierstrassP[...]])
# documented in oracles.txt.

using Printf

const HERE = @__DIR__
const PROJECT_ROOT = abspath(joinpath(HERE, "..", "..", ".."))
const ORACLES_WL  = joinpath(HERE, "oracles.txt")
const ORACLES_PY  = joinpath(HERE, "oracles_python.txt")
const PINNED      = joinpath(PROJECT_ROOT, "test", "_oracle_coefficients.jl")

# ─── Load both oracle files into a fresh module so top-level assignments
# become module-level bindings we can introspect.

module _OracleWL end
module _OraclePy end

function load_into(mod, path)
    src = read(path, String)
    Base.include_string(mod, src, path)
end

load_into(_OracleWL, ORACLES_WL)
load_into(_OraclePy, ORACLES_PY)

# ─── Cross-check 3.1.1: exp(z) Float64 coeffs.
let
    a = _OracleWL.c_3_1_1_exp_o10
    b = _OraclePy.c_3_1_1_exp_o10_py
    @assert length(a) == length(b) == 11 "3.1.1: length mismatch"
    for k in eachindex(a)
        Δ = abs(a[k] - b[k])
        rel = Δ / max(abs(a[k]), abs(b[k]), 1e-300)
        @assert rel < 1e-14 "3.1.1: c[$(k-1)] disagrees: WL=$(a[k]) PY=$(b[k]) rel=$rel"
    end
    println("3.1.1 exp(z) order 10:        wl ≡ py (max rel 1e-14)")
end

# ─── Cross-check 3.1.2: Bessel-ratio Float64 coeffs.
let
    a = _OracleWL.c_3_1_2_bessel_o14
    b = _OraclePy.c_3_1_2_bessel_o14_py
    @assert length(a) == length(b) == 15 "3.1.2: length mismatch"
    for k in eachindex(a)
        Δ = abs(a[k] - b[k])
        rel = Δ / max(abs(a[k]), abs(b[k]), 1e-300)
        @assert rel < 1e-14 "3.1.2: c[$(k-1)] disagrees: WL=$(a[k]) PY=$(b[k]) rel=$rel"
    end
    println("3.1.2 Bessel ratio order 14:  wl ≡ py (max rel 1e-14)")
end

# ─── Cross-check 3.1.3: wolframscript internal — AsymptoticDSolveValue vs
# Series[WeierstrassP[z + c1, {0, c2}]]. Both should agree to Float64 precision.
let
    a = _OracleWL.c_3_1_3_weierstrass_o30
    b = _OracleWL.c_3_1_3_weierstrass_o30_via_P
    @assert length(a) == length(b) == 31 "3.1.3: length mismatch"
    max_rel = 0.0
    for k in eachindex(a)
        Δ = abs(a[k] - b[k])
        rel = Δ / max(abs(a[k]), abs(b[k]), 1e-300)
        max_rel = max(max_rel, rel)
        @assert rel < 1e-13 "3.1.3: c[$(k-1)]: AsympDSV=$(a[k]) WeierP=$(b[k]) rel=$rel"
    end
    g3 = _OracleWL.c_3_1_3_g3_check
    @assert abs(g3 - 2.0) < 1e-13 "3.1.3: g_3 = $g3 doesn't match FW 2011 c_2 = 2"
    @printf("3.1.3 Weierstrass order 30:   AsympDSV ≡ Series[WeierstrassP] (max rel %.2e); g3=%.16f\n", max_rel, g3)
end

# ─── Cross-check 3.1.4: BigFloat-256 strings parse to same value (78-digit match).
let
    setprecision(BigFloat, 256) do
        a_str = _OracleWL.c_3_1_4_exp_o60_str
        b_str = _OraclePy.c_3_1_4_exp_o60_py_str
        @assert length(a_str) == length(b_str) == 61 "3.1.4: length mismatch"
        for k in eachindex(a_str)
            a = parse(BigFloat, a_str[k])
            b = parse(BigFloat, b_str[k])
            Δ = abs(a - b)
            scale = max(abs(a), abs(b), BigFloat(2)^(-256))
            rel = Δ / scale
            @assert rel < BigFloat(2)^(-200) "3.1.4: c[$(k-1)]: WL=$(a_str[k]) PY=$(b_str[k]) rel=$rel"
        end
        println("3.1.4 1/k! BigFloat-256:      wl ≡ py (max rel 2^-200)")
    end
end

# ─── Emit canonical test/_oracle_coefficients.jl.
# This is the file the test suite includes. It contains the wolframscript-
# pinned values (primary oracle), with Python cross-validation enforced
# above. We do NOT regenerate this file silently in CI — re-run this
# verify.jl after any oracle update.
open(PINNED, "w") do io
    print(io, """
# test/_oracle_coefficients.jl — Phase 3 oracle, pinned values.
#
# This file is auto-generated by:
#   external/probes/coefficients-oracle/verify.jl
# from:
#   external/probes/coefficients-oracle/oracles.txt          (wolframscript)
#   external/probes/coefficients-oracle/oracles_python.txt   (sympy/mpmath cross-check)
#
# Do NOT hand-edit. Re-run capture.wl + capture.py + verify.jl to
# update; verify.jl asserts cross-oracle agreement before writing.

""")
    # Float64 vectors — copy Julia-readable lines verbatim from oracles.txt.
    wl_text = read(ORACLES_WL, String)
    print(io, wl_text)
end
println("Wrote ", PINNED)
